def get_mock_slots(specialty=None):
    if specialty:
        filtered = [s for s in FULL_SCHEDULE if s["specialty"].lower() == specialty.lower()]
        return filtered[:8] if filtered else FULL_SCHEDULE[:4]
    return FULL_SCHEDULE[:20]


# Database
def get_db():
    conn = sqlite3.connect(DB_PATH)
    conn.row_factory = sqlite3.Row
    return conn


def init_db():
    conn = get_db()

    conn.execute("""
        CREATE TABLE IF NOT EXISTS leads (
            lead_id    TEXT PRIMARY KEY,
            name       TEXT DEFAULT 'Unknown',
            contact    TEXT,
            service    TEXT DEFAULT 'Other',
            channel    TEXT DEFAULT 'web',
            score      TEXT DEFAULT 'Unscored',
            status     TEXT DEFAULT 'Captured',
            created_at TEXT
        )
    """)

    conn.execute("""
        CREATE TABLE IF NOT EXISTS messages (
            id        INTEGER PRIMARY KEY AUTOINCREMENT,
            lead_id   TEXT,
            sender    TEXT,
            content   TEXT,
            timestamp TEXT
        )
    """)

    conn.execute("""
        CREATE TABLE IF NOT EXISTS appointments (
            appointment_id TEXT PRIMARY KEY,
            lead_id        TEXT,
            doctor         TEXT,
            specialty      TEXT,
            date           TEXT,
            time           TEXT,
            instructions   TEXT,
            created_at     TEXT
        )
    """)

    conn.execute("""
        CREATE TABLE IF NOT EXISTS patient_appointments (
            appointment_id TEXT PRIMARY KEY,
            lead_id        TEXT,
            contact        TEXT,
            name           TEXT,
            doctor         TEXT,
            specialty      TEXT,
            service        TEXT,
            date           TEXT,
            time           TEXT,
            instructions   TEXT,
            status         TEXT DEFAULT 'upcoming',
            booked_at      TEXT
        )
    """)

    conn.execute("""
        CREATE TABLE IF NOT EXISTS model_records (
            id         INTEGER PRIMARY KEY AUTOINCREMENT,
            lead_id    TEXT,
            record     TEXT,
            created_at TEXT
        )
    """)

    conn.execute("""
        CREATE TABLE IF NOT EXISTS patient_sessions (
            id           INTEGER PRIMARY KEY AUTOINCREMENT,
            patient_id   TEXT,
            name         TEXT,
            phone        TEXT,
            logged_in_at TEXT
        )
    """)

