def generate_lead_id():
    conn  = get_db()
    count = conn.execute("SELECT COUNT(*) FROM leads").fetchone()[0]
    conn.close()
    return "L" + str(count + 1).zfill(3)


def success(data):
    return jsonify({ "status": "success", "data": data })


def error(message, code=400):
    return jsonify({ "status": "error", "message": message }), code


def save_model_record(conn, record_type, data):
    """Save a model-format JSON record for audit and sync."""
    import json as _json
    try:
        conn.execute(
            "INSERT INTO model_records (lead_id, record, created_at) VALUES (?,?,?)",
            (data.get("lead_id"), _json.dumps(data), datetime.now().isoformat())
        )
    except Exception as e:
        print("model record save error: " + str(e))


