# Patient login
@app.route('/api/patient/login', methods=['POST'])
def patient_login():
    body  = request.get_json() or {}
    name  = (body.get('name')  or '').strip().lower()
    phone = (body.get('phone') or '').strip()

    if not name or not phone:
        return error("Name and phone number are required.")

    match = next(
        (p for p in PREDEFINED_PATIENTS
         if p['name'].lower() == name and p['phone'] == phone),
        None
    )

    if not match:
        return error("Name and phone number do not match our records.", 401)

    try:
        conn = get_db()
        conn.execute(
            "INSERT INTO patient_sessions (patient_id, name, phone, logged_in_at) VALUES (?,?,?,?)",
            (match['patient_id'], match['name'], match['phone'], datetime.now().isoformat())
        )
        conn.commit()
        conn.close()
    except Exception as e:
        print("Session log error: " + str(e))

    return success({
        "patient_id": match['patient_id'],
        "name":       match['name'],
        "phone":      match['phone'],
    })


