# Chat with Custom AI Model
@app.route('/api/chat', methods=['POST'])
def chat():
    body = request.get_json() or {}
    lead_id = body.get('lead_id', '')
    message = body.get('message', '')
    stage = body.get('stage', 'greeting')
    now = datetime.now().isoformat()

    conn = get_db()
    conn.execute(
        "INSERT INTO messages (lead_id,sender,content,timestamp) VALUES (?,?,?,?)",
        (lead_id, "user", message, now)
    )
    conn.commit()

    reply = None
    new_stage = stage
    detected_service = None  # Will be set after lead_data is loaded

    try:
        lead_row = conn.execute("SELECT * FROM leads WHERE lead_id=?", (lead_id,)).fetchone()
        lead_data = dict(lead_row) if lead_row else {}
        service = lead_data.get("service", "General Medicine")
        detected_service = service  # Initialize from current lead's service

        if stage in ("greeting", "start"):
            intent = detect_service(message)
            service = intent if isinstance(intent, str) else intent.get("service_category", "General Medicine")

            conn.execute("UPDATE leads SET service=? WHERE lead_id=?", (service, lead_id))
            conn.commit()

            features = get_conversation_flow(service)
            if features:
                reply = opening_message(service) + "\n" + generate_question(features[0], service)
                new_stage = "0"
            else:
                reply = "How can I help you today?"
                new_stage = "done"
            detected_service = service

        elif stage.isdigit():
            idx = int(stage)
            features = get_conversation_flow(service)

            if idx + 1 < len(features):
                # Ask next question
                reply = generate_question(features[idx + 1], service)
                new_stage = str(idx + 1)
            else:
                # Finished asking questions. Gather answers and score.
                msg_rows = conn.execute(
                    "SELECT sender, content FROM messages WHERE lead_id=? ORDER BY id",
                    (lead_id,)
                ).fetchall()

                user_msgs = [r["content"] for r in msg_rows if r["sender"] == "user"]
                answers = {}
                q_path = []
                for i, feature in enumerate(features):
                    msg_idx = i + 1
                    if msg_idx < len(user_msgs):
                        answers[feature] = user_msgs[msg_idx]
                        q_path.append(feature)

                # Fetch full lead info
                lead_name = answers.get("name", lead_data.get("name", "Unknown"))
                lead_phone = answers.get("phone", lead_data.get("contact", ""))
                if not lead_phone: lead_phone = ""
                if not lead_name: lead_name = "Unknown"

                # Use custom model to score lead
                score = score_lead(answers)

                outcome = "converted" if score == "Hot" else "lost" if score == "Cold" else "follow_up"
                status = "Converted" if score == "Hot" else "Lost" if score == "Cold" else "Qualified"

                conn.execute(
                    "UPDATE leads SET score=?, status=?, name=?, contact=? WHERE lead_id=?",
                    (score, status, lead_name, lead_phone, lead_id)
                )
                conn.commit()

                # Save model-format record
                import json as _json
                model_record = {
                    "lead_id": lead_id,
                    "service": service,
                    "question_path": q_path,
                    "answers": dict(answers, name=lead_name, phone=lead_phone),
                    "score": score,
                    "outcome": outcome,
                    "timestamp": datetime.now().isoformat()
                }
                save_model_record(conn, "lead", model_record)
                conn.commit()

                detected_service = service

                if score in ("Hot", "Warm"):
                    reply = "Based on what you have shared, I would recommend booking an appointment as soon as possible. Shall I check available slots for you?"
                    new_stage = "booking"
                else:
                    # Save follow-up record
                    followup_record = {
                        "patient_name": lead_name,
                        "contact": lead_phone,
                        "service": service,
                        "action": "information_pack_sent",
                        "follow_up_call_in_days": 2,
                        "status": "follow_up_scheduled"
                    }
                    save_model_record(conn, "followup", followup_record)
                    conn.commit()
                    reply = "Thank you for reaching out! We will have one of our care coordinators follow up with you soon. Is there anything else I can help with?"
                    new_stage = "nurture"

        elif stage == "booking":
            if message.lower() in ("yes", "yeah", "yep", "sure", "ok", "please"):
                # Fetch lead for name/contact
                from ai.fresh_new_combine_final.ai_module import handle_lead_action
                
                lead_name = lead_data.get("name", "Unknown")
                lead_phone = lead_data.get("contact", "")
                score = lead_data.get("score", "Hot")
                
                action_result = handle_lead_action(lead_id, score, service, lead_name, lead_phone)
                
                if action_result.get("status") == "appointment_booked":
                    booking_dtls = action_result.get("details", {})
                    # Insert into patient_appointments
                    try:
                        conn.execute("""
                            INSERT OR IGNORE INTO patient_appointments
                            (appointment_id,lead_id,contact,name,doctor,specialty,service,date,time,instructions,status,booked_at)
                            VALUES (?,?,?,?,?,?,?,?,?,?,?,?)
                        """, (
                            booking_dtls.get("confirmation_id"),
                            lead_id,
                            lead_phone,
                            lead_name,
                            booking_dtls.get("doctor"),
                            booking_dtls.get("specialty", service),
                            service,
                            booking_dtls.get("date"),
                            booking_dtls.get("time"),
                            booking_dtls.get("instructions", ""),
                            "upcoming",
                            datetime.now().isoformat()
                        ))
                        conn.commit()
                    except Exception as e:
                        print("Error saving appointment:", e)
                        
                    reply = f"Great! Your appointment is confirmed with {booking_dtls.get('doctor')} on {booking_dtls.get('date')} at {booking_dtls.get('time')}."
                else:
                    reply = action_result.get("message", "I couldn't find an available slot right now, but I have noted your request.")
            else:
                reply = "Okay, I won't book anything for now. Is there anything else I can help with?"
            new_stage = "done"

        elif stage == "nurture":
            reply = "I've made a note of that. We will be in touch soon!"
            new_stage = "done"

        elif stage == "done":
            reply = "I'm here to help."
            new_stage = "done"

        else:
            reply = "Thank you for reaching out! Could you tell me more about your symptoms?"
            new_stage = "0"

    except Exception as e:
        print("AI error: " + str(e))
        import traceback
        traceback.print_exc()
        reply = "Thank you for reaching out! Could you tell me more about your symptoms?"
        new_stage = "0"

    if not reply:
        reply = "I'm here to help."

    # Always persist service back to what the lead has (may have been updated above)
    if not detected_service:
        lead_row_final = conn.execute("SELECT service FROM leads WHERE lead_id=?", (lead_id,)).fetchone()
        detected_service = dict(lead_row_final)["service"] if lead_row_final else "General Medicine"

    return success({
        "reply": reply,
        "stage": new_stage,
        "service": detected_service,
        "lead_id": lead_id
    })


# Analytics
@app.route('/api/analytics', methods=['GET'])
def get_analytics():
    conn      = get_db()
    total     = conn.execute("SELECT COUNT(*) FROM leads").fetchone()[0]
    converted = conn.execute("SELECT COUNT(*) FROM leads WHERE status='Converted'").fetchone()[0]
    lost      = conn.execute("SELECT COUNT(*) FROM leads WHERE status='Lost'").fetchone()[0]
    rate      = round((converted / total * 100), 1) if total > 0 else 0

    chan_rows  = conn.execute("SELECT channel, COUNT(*) as cnt FROM leads GROUP BY channel").fetchall()
    by_channel = { r["channel"]: round(r["cnt"] / total * 100) for r in chan_rows } if total > 0 else {}

    svc_rows   = conn.execute("SELECT service, COUNT(*) as cnt FROM leads GROUP BY service").fetchall()
    by_service = { r["service"]: round(r["cnt"] / total * 100) for r in svc_rows } if total > 0 else {}

    conn.close()
    return success({
        "total_leads":     total,
        "converted":       converted,
        "lost":            lost,
        "conversion_rate": rate,
        "by_channel":      by_channel,
        "by_service":      by_service,
    })


# Fetch model records
@app.route('/api/model_records/<lead_id>', methods=['GET'])
def get_model_record(lead_id):
    import os
    import json
    import glob
    d = os.path.join(os.path.dirname(__file__), "..", "glitchcon", "model_records")
    pattern = os.path.join(d, f"lead_{lead_id}_*.json")
    files = glob.glob(pattern)
    if not files:
        return success({"record": None})
    
    # Get the latest file if there are multiple
    latest_file = max(files, key=os.path.getmtime)
    try:
        with open(latest_file, "r") as f:
            record = json.load(f)
        return success({"record": record})
    except Exception as e:
        print("Error reading model record:", str(e))
        return success({"record": None})


# Appointment availability
@app.route('/api/appointments/availability', methods=['GET'])
def get_availability():
    specialty = request.args.get('specialty', '')
    date      = request.args.get('date', '')
    print(f"[DEBUG] Availability requested for specialty='{specialty}' date='{date}'")
    slots     = [s for s in FULL_SCHEDULE if (not specialty or s["specialty"].lower() == specialty.lower())]
    # Fallback: if no slots found for the given specialty, return any available slots
    if not slots and specialty:
        print(f"[DEBUG] No slots found for specialty='{specialty}', falling back to all available slots")
        slots = FULL_SCHEDULE
    if date:
        # Return slots on requested date first, then fallback to future slots
        on_date = [s for s in slots if s["date"] == date]
        after   = [s for s in slots if s["date"] > date]
        result  = (on_date + after)[:8]
    else:
        result = slots[:8]
    print(f"[DEBUG] Returning {len(result)} slots")
    return success({ "slots": result })


# Book appointment
@app.route('/api/appointment/book', methods=['POST'])
def book_appointment():
    body    = request.get_json() or {}
    lead_id = body.get('lead_id', '')
    slot_id = body.get('slot_id', '')

    all_slots = get_mock_slots()
    slot = next((s for s in all_slots if s["slot_id"] == slot_id), all_slots[0])

    conf_id = "CONF-" + lead_id + "-" + slot_id
    instructions_map = {
        "Cardiology":       "Bring previous ECG and BP reports. Avoid heavy meals. Arrive 15 min early.",
        "Orthopedics":      "Bring X-ray reports. Wear comfortable clothing. Avoid painkillers 4 hrs before.",
        "Diagnostics":      "Fast for 8 hours before the test. Bring previous lab reports.",
        "Neurology":        "Bring MRI/CT scans if available. Avoid caffeine 4 hrs before.",
        "General Medicine": "Bring your previous prescriptions and ID proof.",
        "Pediatrics":       "Bring vaccination records. Parent or guardian must accompany.",
        "Oncology":         "Bring all previous test reports. A caregiver is recommended.",
        "Other":            "Arrive 15 minutes early and bring any relevant medical records.",
    }
    instructions = instructions_map.get(slot.get("specialty", "Other"), "Arrive 15 minutes early with your medical records.")
    now = datetime.now().isoformat()

    conn = get_db()
    conn.execute(
        "INSERT OR REPLACE INTO appointments (appointment_id,lead_id,doctor,specialty,date,time,instructions,created_at) VALUES (?,?,?,?,?,?,?,?)",
        (conf_id, lead_id, slot["doctor"], slot["specialty"], slot["date"], slot["time"], instructions, now)
    )
    conn.execute("UPDATE leads SET status='Converted', score='Hot' WHERE lead_id=?", (lead_id,))

    # Save booking model record
    import json as _json
    lead_row  = conn.execute("SELECT * FROM leads WHERE lead_id=?", (lead_id,)).fetchone()
    lead_data = dict(lead_row) if lead_row else {}
    booking_record = {
        "booking_id":       conf_id,
        "patient_name":     lead_data.get("name", "Unknown"),
        "contact":          lead_data.get("contact"),
        "doctor_name":      slot["doctor"],
        "service_provided": slot["specialty"],
        "date":             slot["date"],
        "time":             slot["time"],
        "status":           "upcoming"
    }
    save_model_record(conn, "booking", booking_record)
    conn.commit()
    conn.close()

    return success({
        "confirmation_id": conf_id,
        "lead_id":         lead_id,
        "doctor":          slot["doctor"],
        "specialty":       slot["specialty"],
        "date":            slot["date"],
        "time":            slot["time"],
        "instructions":    instructions,
    })


